#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;package=org.archphene.linux.p0392be9c9f103a39d951c2f39c3644d2;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--kcalc-package)package="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";[[ "$serial" == emulator-* ]] || archphene_die 'display matrix must run on an emulator';activity="$(archphene_launcher "$package")";old_font="$(archphene_adb_run shell settings get system font_scale|tr -d '\r')";old_night="$(archphene_adb_run shell cmd uimode night|sed -n 's/^Night mode: //p'|tr -d '\r')";restore(){ archphene_adb_run shell wm size reset >/dev/null 2>&1 || true;archphene_adb_run shell wm density reset >/dev/null 2>&1 || true;archphene_adb_run shell settings put system font_scale "$old_font" >/dev/null 2>&1 || true;archphene_adb_run shell cmd uimode night "$old_night" >/dev/null 2>&1 || true;};trap restore EXIT;profiles=('phone-light 1080 2400 420 1.0 no' 'phone-landscape-dark 2400 1080 420 1.0 yes' 'tablet-light 1280 1920 280 1.15 no' 'tablet-landscape-dark 1920 1280 280 1.15 yes' 'docked-dark 1920 1080 240 1.0 yes');pid=;child=;for row in "${profiles[@]}";do read -r name width height density font night<<<"$row";archphene_adb_run shell wm size "${width}x${height}";archphene_adb_run shell wm density "$density";archphene_adb_run shell settings put system font_scale "$font";archphene_adb_run shell cmd uimode night "$night";archphene_adb_run shell am start -W -n "$activity" >/dev/null;sleep 3;current="$(archphene_android_pid "$package")";current_child="$(archphene_linux_loader_pid "$current")";if [[ -n "$pid" ]];then [[ "$current" == "$pid" && "$current_child" == "$child" ]] || archphene_die "$name restarted KCalc";else pid="$current";child="$current_child";fi;ui="$(archphene_capture_ui "matrix-$name")";[[ "$ui" == *android.widget.ImageView* ]] || archphene_die "$name missing viewport";archphene_note "$name passed: ${width}x$height density=$density font=$font night=$night";done;archphene_note "Release display matrix passed on $serial with stable Android PID $pid and Linux PID $child."
